  1→import React, { useState, useEffect } from 'react';
  2→import { User } from '../types';
  3→import { Fuel, Check, CreditCard, Loader2, Droplet, Database, ArrowLeft, ShieldCheck, Lock, Infinity, CheckCircle2, FileText, Download, XCircle, LayoutDashboard, RefreshCcw, Wrench } from 'lucide-react';
  4→import jsPDF from 'jspdf';
  5→import StripeCheckout from '../components/StripeCheckout';
  6→import PageHeader from '../components/layout/PageHeader';
  7→
  8→interface Props {
  9→  onBack: () => void;
 10→  onRecharge: (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => void;
 11→  user: User | null;
 12→  onNavigate?: (view: string) => void;
 13→  initialPackId?: number | null;
 14→}
 15→
 16→const Recharge: React.FC<Props> = ({ onBack, onRecharge, user, onNavigate, initialPackId }) => {
 17→  const [viewMode, setViewMode] = useState<'list' | 'checkout' | 'result'>('list');
 18→  const [paymentStatus, setPaymentStatus] = useState<'idle' | 'success' | 'error'>('idle');
 19→  const [selectedPack, setSelectedPack] = useState<typeof packs[0] | null>(null);
 20→  const [isProcessing, setIsProcessing] = useState(false);
 21→  const [invoiceId, setInvoiceId] = useState<string>('');
 22→
 23→  const packs = [
 24→    {
 25→      id: 1,
 26→      name: "Le Jerrican",
 27→      amount: 50,
 28→      price: 15,
 29→      icon: <Droplet size={32} />,
 30→      popular: false,
 31→      level: 'free' as const,
 32→      features: ["Idéal pour un audit ponctuel", "Valable 1 an"]
 33→    },
 34→    {
 35→      id: 2,
 36→      name: "La Pompe",
 37→      amount: 200,
 38→      price: 49,
 39→      icon: <Fuel size={32} />,
 40→      popular: true,
 41→      level: 'pro' as const,
 42→      features: ["Pour les optimisations régulières", "Support prioritaire", "+10% Bonus offert"]
 43→    },
 44→    {
 45→      id: 3,
 46→      name: "La Citerne",
 47→      amount: 1000,
 48→      price: 199,
 49→      icon: <Database size={32} />,
 50→      popular: false,
 51→      level: 'enterprise' as const,
 52→      features: ["Usage intensif / Agence", "Accès API Beta", "+20% Bonus offert"]
 53→    }
 54→  ];
 55→
 56→  // Effet pour sélectionner automatiquement un pack si initialPackId est fourni
 57→  useEffect(() => {
 58→    if (initialPackId) {
 59→        const targetPack = packs.find(p => p.id === initialPackId);
 60→        if (targetPack) {
 61→            setSelectedPack(targetPack);
 62→            setViewMode('checkout');
 63→        }
 64→    }
 65→  }, [initialPackId]);
 66→
 67→  const handleSelectPack = (pack: typeof packs[0]) => {
 68→    setSelectedPack(pack);
 69→    setViewMode('checkout');
 70→    window.scrollTo({ top: 0, behavior: 'smooth' });
 71→  };
 72→
 73→  const handleConfirmPayment = () => {
 74→    if (!selectedPack) return;
 75→    setIsProcessing(true);
 76→    setPaymentStatus('idle');
 77→    
 78→    // Simulation délai paiement et résultat aléatoire (90% de succès pour l'UX)
 79→    setTimeout(() => {
 80→      const isSuccess = Math.random() > 0.1;
 81→      
 82→      if (isSuccess) {
 83→        onRecharge(selectedPack.amount, selectedPack.level);
 84→        const newInvoiceId = `INV-${new Date().getFullYear()}-${Math.floor(Math.random() * 10000).toString().padStart(4, '0')}`;
 85→        setInvoiceId(newInvoiceId);
 86→        setPaymentStatus('success');
 87→      } else {
 88→        setPaymentStatus('error');
 89→      }
 90→      
 91→      setIsProcessing(false);
 92→      setViewMode('result');
 93→      window.scrollTo({ top: 0, behavior: 'smooth' });
 94→    }, 2000);
 95→  };
 96→
 97→  const generateInvoicePDF = () => {
 98→    if (!selectedPack || !user) return;
 99→
100→    const doc = new jsPDF();
101→    const priceHT = selectedPack.price;
102→    const tva = priceHT * 0.20;
103→    const totalTTC = priceHT + tva;
104→    const date = new Date().toLocaleDateString('fr-FR');
105→
106→    // Header
107→    doc.setFontSize(22);
108→    doc.setFont("helvetica", "bold");
109→    doc.text("CitedBy.ai", 20, 20);
110→    
111→    doc.setFontSize(10);
112→    doc.setFont("helvetica", "normal");
113→    doc.text("Facture N° " + invoiceId, 20, 30);
114→    doc.text("Date : " + date, 20, 35);
115→
116→    // Client Info
117→    doc.text("Facturé à :", 140, 30);
118→    doc.setFont("helvetica", "bold");
119→    doc.text(user.name || "Client", 140, 35);
120→    doc.setFont("helvetica", "normal");
121→    doc.text(user.email || "", 140, 40);
122→
123→    // Line Items Header
124→    doc.line(20, 55, 190, 55);
125→    doc.setFont("helvetica", "bold");
126→    doc.text("Description", 20, 62);
127→    doc.text("Quantité", 120, 62);
128→    doc.text("Montant HT", 160, 62);
129→    doc.line(20, 66, 190, 66);
130→
131→    // Item
132→    doc.setFont("helvetica", "normal");
133→    doc.text(`Pack GTO Gas: ${selectedPack.name} (${selectedPack.amount} crédits)`, 20, 75);
134→    doc.text("1", 125, 75);
135→    doc.text(`${priceHT.toFixed(2)} €`, 160, 75);
136→
137→    // Totals
138→    doc.line(20, 90, 190, 90);
139→    doc.text("Sous-total HT :", 130, 100);
140→    doc.text(`${priceHT.toFixed(2)} €`, 160, 100);
141→    
142→    doc.text("TVA (20%) :", 130, 107);
143→    doc.text(`${tva.toFixed(2)} €`, 160, 107);
144→
145→    doc.setFont("helvetica", "bold");
146→    doc.setFontSize(12);
147→    doc.text("Total TTC :", 130, 117);
148→    doc.text(`${totalTTC.toFixed(2)} €`, 160, 117);
149→
150→    // Footer
151→    doc.setFontSize(8);
152→    doc.setFont("helvetica", "italic");
153→    doc.text("Merci de votre confiance. Cette facture a été réglée par carte bancaire.", 20, 140);
154→    doc.text("CitedBy Inc. - 123 Avenue de l'IA, Paris, France - SIRET 123 456 789", 20, 280);
155→
156→    doc.save(`Facture_${invoiceId}.pdf`);
157→  };
158→
159→  const renderList = () => (
160→    <div className="animate-in fade-in slide-in-from-left duration-500">
161→        <div className="text-center mb-16">
162→            <div className="inline-flex items-center justify-center w-16 h-16 bg-accent/20 rounded-2xl mb-6 text-accent border border-accent/20 shadow-[0_0_30px_rgba(168,85,247,0.2)]">
163→            <Fuel size={32} />
164→            </div>
165→            <h1 className="text-4xl font-bold text-white mb-4">GTO <span className="gradient-text">Gas Station</span></h1>
166→            <p className="text-gray-500 max-w-xl mx-auto text-lg">
167→            Le carburant essentiel pour propulser votre visibilité dans les moteurs de réponse.
168→            <br />
169→            <span className="text-sm mt-2 block text-gray-500">Solde actuel : <span className="text-white font-bold">{user?.credits || 0} Gas</span></span>
170→            </p>
171→        </div>
172→
173→        <div className="grid md:grid-cols-3 gap-8 w-full">
174→            {packs.map((pack) => (
175→            <div 
176→                key={pack.id} 
177→                className={`relative ninja-card p-8 flex flex-col transition-all duration-300 hover:transform hover:-translate-y-2 ${
178→                pack.popular
179→                    ? 'gradient-border !border-purple-500/30 shadow-[0_0_40px_rgba(168,85,247,0.15)] scale-105 z-10'
180→                    : ''
181→                }`}
182→            >
183→                {pack.popular && (
184→                <>
185→                <div className="absolute -top-4 left-1/2 -translate-x-1/2 bg-gradient-to-r from-purple-500 to-violet-500 text-white font-bold text-xs px-4 py-1.5 rounded-full uppercase tracking-wider shadow-lg shadow-purple-900/40 flex items-center gap-1.5">
186→                    <span className="animate-pulse">⭐</span> Meilleure Offre
187→                </div>
188→                <div className="absolute -top-px -left-px -right-px -bottom-px rounded-2xl bg-gradient-to-r from-purple-500/20 to-violet-500/20 -z-10 blur-sm" />
189→                </>
190→                )}
191→
192→                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center mb-6 ${pack.popular ? 'bg-accent/20 text-accent' : 'bg-white/[0.04] text-gray-500'}`}>
193→                {pack.icon}
194→                </div>
195→
196→                <h3 className="text-xl font-bold text-white mb-2">{pack.name}</h3>
197→                <div className="flex items-baseline gap-1 mb-6">
198→                <span className="text-4xl font-bold gradient-text">{pack.amount}</span>
199→                <span className="text-sm text-gray-500 font-medium">Gas</span>
200→                </div>
201→
202→                <ul className="space-y-3 mb-8 flex-1">
203→                {pack.features.map((feat, i) => (
204→                    <li key={i} className="flex items-start gap-3 text-sm text-gray-300">
205→                    <Check size={16} className={`mt-0.5 ${pack.popular ? 'text-accent' : 'text-gray-500'}`} />
206→                    {feat}
207→                    </li>
208→                ))}
209→                </ul>
210→
211→                <div className="border-t border-white/[0.08] pt-6 mb-6">
212→                <div className="flex justify-between items-center mb-2">
213→                    <span className="text-gray-500">Prix HT</span>
214→                    <span className="text-xl font-bold text-white">{pack.price}€</span>
215→                </div>
216→                </div>
217→
218→                <button
219→                onClick={() => handleSelectPack(pack)}
220→                className="w-full py-3.5 btn-gradient font-bold flex items-center justify-center gap-2 transition-all"
221→                >
222→                    <CreditCard size={18} /> Acheter
223→                </button>
224→            </div>
225→            ))}
226→        </div>
227→
228→        <p className="text-center text-gray-500 text-xs mt-12">
229→            Paiement sécurisé via Stripe • Facture disponible instantanément • TVA non incluse
230→        </p>
231→    </div>
232→  );
233→
234→  const renderCheckout = () => {
235→    if (!selectedPack) return null;
236→
237→    const priceHT = selectedPack.price;
238→    const tva = priceHT * 0.20;
239→    const totalTTC = priceHT + tva;
240→
241→    // Logique Upsell
242→    const showCiterneUpsell = selectedPack.name !== "La Citerne";
243→    const showSubscriptionUpsell = user?.plan === 'free';
244→
245→    return (
246→        <div className="animate-in fade-in slide-in-from-right duration-500">
247→            <div className="grid lg:grid-cols-12 gap-8">
248→
249→                {/* Colonne Gauche: Paiement */}
250→                <div className="lg:col-span-8">
251→                    <StripeCheckout
252→                      mode="one-time"
253→                      productName={selectedPack.name}
254→                      productDescription={`Pack de ${selectedPack.amount} cr\u00e9dits GTO Gas`}
255→                      productIcon={selectedPack.icon}
256→                      amount={totalTTC}
257→                      amountDetails={[
258→                        { label: 'Prix Unitaire HT', value: `${priceHT.toFixed(2)} \u20ac` },
259→                        { label: 'Frais de service', value: '0.00 \u20ac' },
260→                        { label: 'TVA (20%)', value: `${tva.toFixed(2)} \u20ac` },
261→                        { label: 'Total TTC', value: `${totalTTC.toFixed(2)} \u20ac`, highlight: true, separator: true },
262→                      ]}
263→                      userEmail={user?.email}
264→                      onConfirm={handleConfirmPayment}
265→                      onBack={() => setViewMode('list')}
266→                      isProcessing={isProcessing}
267→                    />
268→                </div>
269→
270→                {/* Colonne Droite: Upsells */}
271→                <div className="lg:col-span-4 space-y-4">
272→                    <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wider mb-2">Recommandé pour vous</h3>
273→                    
274→                    {/* Upsell Citerne */}
275→                    {showCiterneUpsell && (
276→                        <div className="bg-gradient-to-br from-purple-900/40 to-black border border-purple-500/30 p-5 rounded-2xl relative overflow-hidden group cursor-pointer hover:border-purple-500/60 transition-all" onClick={() => setSelectedPack(packs[2])}>
277→                            <div className="absolute top-0 right-0 px-2 py-1 bg-purple-500 text-white text-[10px] font-bold rounded-bl-lg">
278→                                Meilleur Prix / Unité
279→                            </div>
280→                            <div className="flex items-center gap-3 mb-3">
281→                                <div className="p-2 bg-purple-500/20 rounded-full text-purple-400">
282→                                    <Database size={20} />
283→                                </div>
284→                                <div>
285→                                    <h4 className="font-bold text-white text-sm">Passez à la Citerne</h4>
286→                                    <p className="text-xs text-purple-200/70">Économisez 60%</p>
287→                                </div>
288→                            </div>
289→                            <p className="text-xs text-gray-300 mb-3 leading-relaxed">
290→                                Obtenez <strong>1000 Crédits</strong> pour seulement 199€. Idéal pour les agences ou les refontes complètes.
291→                            </p>
292→                            <button className="w-full py-2 border border-white/[0.08] bg-white/[0.04] rounded-full text-purple-400 text-xs font-bold transition-colors hover:bg-white/[0.08]">
293→                                Choisir ce pack (199€)
294→                            </button>
295→                        </div>
296→                    )}
297→
298→                    {/* Upsell Abonnement */}
299→                    {showSubscriptionUpsell && (
300→                        <div className="bg-gradient-to-br from-purple-900/40 to-black border border-purple-500/30 p-5 rounded-2xl relative overflow-hidden group cursor-pointer hover:border-purple-500/60 transition-all">
301→                            <div className="absolute top-0 right-0 px-2 py-1 bg-purple-500 text-white text-[10px] font-bold rounded-bl-lg flex items-center gap-1">
302→                                <Infinity size={10} /> Mensuel
303→                            </div>
304→                            <div className="flex items-center gap-3 mb-3">
305→                                <div className="p-2 bg-purple-500/20 rounded-full text-purple-400">
306→                                    <ShieldCheck size={20} />
307→                                </div>
308→                                <div>
309→                                    <h4 className="font-bold text-white text-sm">Activez le Monitoring</h4>
310→                                    <p className="text-xs text-purple-200/70">La Source</p>
311→                                </div>
312→                            </div>
313→                            <p className="text-xs text-gray-300 mb-3 leading-relaxed">
314→                                Ne perdez pas vos positions. Ajoutez l'indexation continue et la détection d'hallucinations.
315→                            </p>
316→                            <div className="flex items-center gap-2 mb-3">
317→                                <span className="text-lg font-bold text-white">89€</span>
318→                                <span className="text-xs text-gray-500">/mois</span>
319→                            </div>
320→                            <button className="w-full py-2 btn-gradient text-xs font-bold transition-colors">
321→                                Ajouter l'abonnement
322→                            </button>
323→                        </div>
324→                    )}
325→
326→                    {!showCiterneUpsell && !showSubscriptionUpsell && (
327→                        <div className="p-5 rounded-2xl border border-white/[0.06] bg-white/[0.04] text-center">
328→                            <div className="w-12 h-12 bg-purple-400/10 rounded-full flex items-center justify-center text-purple-300 mx-auto mb-3">
329→                                <Check size={24} />
330→                            </div>
331→                            <p className="text-sm text-gray-300 font-medium">Vous avez choisi la meilleure offre pour vos besoins !</p>
332→                        </div>
333→                    )}
334→                </div>
335→            </div>
336→        </div>
337→    );
338→  };
339→
340→  const renderPaymentResult = () => {
341→    if (!selectedPack) return null;
342→    
343→    // Status: ERROR
344→    if (paymentStatus === 'error') {
345→        return (
346→            <div className="flex flex-col items-center justify-center min-h-[60vh] animate-in zoom-in duration-500 max-w-2xl mx-auto">
347→                <div className="w-24 h-24 bg-red-500/20 rounded-full flex items-center justify-center mb-8 border border-red-500/50 shadow-[0_0_40px_rgba(239,68,68,0.3)]">
348→                    <XCircle size={48} className="text-red-500" />
349→                </div>
350→                
351→                <h2 className="text-4xl font-bold text-white mb-2">Paiement <span className="gradient-text">Refusé</span></h2>
352→                <p className="text-gray-500 text-center mb-10 text-lg">
353→                    La transaction n'a pas pu aboutir. Veuillez vérifier vos informations bancaires ou essayer une autre méthode de paiement.
354→                </p>
355→
356→                <div className="flex gap-4 w-full">
357→                    <button
358→                        onClick={() => { setViewMode('list'); }}
359→                        className="flex-1 py-3.5 rounded-full font-bold border border-white/[0.08] bg-white/[0.04] text-white hover:bg-white/[0.08] transition-colors flex items-center justify-center gap-2"
360→                    >
361→                        <ArrowLeft size={18} /> Annuler
362→                    </button>
363→                    <button
364→                        onClick={() => { setViewMode('checkout'); }}
365→                        className="flex-1 py-3.5 btn-gradient font-bold transition-all flex items-center justify-center gap-2"
366→                    >
367→                        <RefreshCcw size={18} /> Réessayer
368→                    </button>
369→                </div>
370→            </div>
371→        );
372→    }
373→
374→    // Status: SUCCESS
375→    const priceHT = selectedPack.price;
376→    const tva = priceHT * 0.20;
377→    const totalTTC = priceHT + tva;
378→
379→    return (
380→        <div className="flex flex-col items-center justify-center min-h-[60vh] animate-in zoom-in duration-500 max-w-2xl mx-auto">
381→            <div className="w-24 h-24 bg-purple-400/20 rounded-full flex items-center justify-center mb-8 border border-purple-400/50 shadow-[0_0_40px_rgba(168,85,247,0.3)]">
382→                <CheckCircle2 size={48} className="text-purple-400" />
383→            </div>
384→            
385→            <h2 className="text-4xl font-sans font-bold text-white mb-2">Paiement Accepté !</h2>
386→            <p className="text-gray-500 text-center mb-10 text-lg">
387→                Merci pour votre commande. Vos crédits <strong>{selectedPack.amount} GTO Gas</strong> ont été ajoutés à votre compte.
388→            </p>
389→
390→            <div className="w-full bg-[#0f1115] border border-white/[0.08] rounded-2xl p-8 mb-8 relative overflow-hidden">
391→                <div className="absolute top-0 right-0 px-3 py-1 bg-white/[0.08] rounded-bl-lg text-xs text-gray-500 font-mono">
392→                    {invoiceId}
393→                </div>
394→                
395→                <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
396→                    <FileText size={20} className="text-purple-400" /> Récapitulatif de commande
397→                </h3>
398→
399→                <div className="space-y-4 text-sm">
400→                    <div className="flex justify-between items-center text-gray-300">
401→                        <span>Produit</span>
402→                        <span className="font-medium text-white">{selectedPack.name}</span>
403→                    </div>
404→                    <div className="flex justify-between items-center text-gray-300">
405→                        <span>Quantité</span>
406→                        <span className="font-medium text-white">1</span>
407→                    </div>
408→                    <div className="flex justify-between items-center text-gray-300 border-b border-white/[0.08] pb-4">
409→                        <span>Date</span>
410→                        <span className="font-medium text-white">{new Date().toLocaleDateString()}</span>
411→                    </div>
412→                    <div className="flex justify-between items-center pt-2">
413→                        <span className="font-bold text-white text-lg">Total Payé</span>
414→                        <span className="font-bold text-xl text-purple-400">{totalTTC.toFixed(2)} €</span>
415→                    </div>
416→                </div>
417→            </div>
418→
419→            {/* Buttons Navigation Succès */}
420→            <div className="flex flex-col md:flex-row gap-4 w-full">
421→                <button 
422→                    onClick={() => { onNavigate ? onNavigate('projects') : onBack(); }}
423→                    className="flex-1 py-3.5 rounded-2xl font-bold bg-white/[0.08] text-white hover:bg-white/20 transition-colors flex items-center justify-center gap-2"
424→                >
425→                    <Wrench size={18} /> Continuer l'analyse
426→                </button>
427→                <button 
428→                    onClick={() => { onNavigate ? onNavigate('plan') : console.log("Navigation vers plan non disponible"); }}
429→                    className="flex-1 py-3.5 rounded-2xl font-bold bg-primary hover:bg-purple-600 text-white transition-all shadow-lg shadow-primary/20 flex items-center justify-center gap-2"
430→                >
431→                    <CreditCard size={18} /> Voir Plan & Facturation
432→                </button>
433→            </div>
434→            
435→            <button 
436→                onClick={generateInvoicePDF}
437→                className="mt-6 text-sm text-gray-500 hover:text-white flex items-center gap-2 transition-colors"
438→            >
439→                <Download size={14} /> Télécharger la facture PDF
440→            </button>
441→        </div>
442→    );
443→  };
444→
445→  return (
446→    <div className="animate-in fade-in duration-500">
447→      <PageHeader title="GTO Gas" description="Rechargez vos crédits" />
448→        {viewMode === 'list' && renderList()}
449→        {viewMode === 'checkout' && renderCheckout()}
450→        {viewMode === 'result' && renderPaymentResult()}
451→    </div>
452→  );
453→};
454→
455→export default Recharge;

   1→import React, { useState, useMemo, useRef, useEffect } from 'react';
