 27→// Helper to convert AnalysisResult to Project format
 28→const mapAnalysisToProject = (analysis: AnalysisResult, index: number): Project => {
 29→  const hostname = new URL(analysis.url).hostname;
 30→  return {
 31→    id: `proj_${index}_${hostname}`,
 32→    name: hostname,
 33→    domain: analysis.url,
 34→    status: 'active',
 35→    lastRun: analysis.timestamp,
 36→    visibilityScore: analysis.globalScore,
 37→    trend: analysis.globalScore > 70 ? 12 : (analysis.globalScore > 50 ? 5 : -5), // Simulé basé sur le score
 38→    nextRun: new Date(new Date(analysis.timestamp).getTime() + 86400000 * 7).toISOString()
 39→  };
 40→};
