132→  // Calculate Pillar Scores from real categories if available
133→  const getPillarScores = () => {
134→    if (!activeAnalysis) {
135→      return {
136→        tech: 50,
137→        sem: 50,
138→        auth: 50
139→      };
140→    }
141→    
142→    const cats = activeAnalysis.categories;
143→    
144→    // Aggregation logic
145→    const techScore = Math.round(
146→      ((cats['technical']?.score || 0) + (cats['ux']?.score || 0) + (cats['freshness']?.score || 0)) / 3
147→    );
148→    
149→    const semScore = Math.round(
150→      ((cats['semantic']?.score || 0) + (cats['content']?.score || 0) + (cats['geo']?.score || 0) + (cats['media']?.score || 0)) / 4
151→    );
