 25→    { label: 'Experience', icon: <UserCheck size={16} />, score: Math.round((auditResult.categories.contentFreshness.score + auditResult.categories.answerFirst.score) / 2) },
 26→    { label: 'Expertise', icon: <GraduationCap size={16} />, score: Math.round((auditResult.categories.faqStructure.score + auditResult.categories.semanticHtml.score) / 2) },
 27→    { label: 'Authority', icon: <BadgeCheck size={16} />, score: Math.round((auditResult.categories.schemaOrg.score + auditResult.categories.metaOptimization.score) / 2) },
 28→    { label: 'Trust', icon: <Shield size={16} />, score: Math.round((auditResult.categories.metaOptimization.score + auditResult.categories.schemaOrg.score + auditResult.categories.answerFirst.score) / 3) },
 29→  ] : [];
